import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Dialog from '@material-ui/core/Dialog';
import ImageList from '@material-ui/core/ImageList';
import ImageListItem from '@material-ui/core/ImageListItem';
// import ListItemText from '@material-ui/core/ListItemText';
// import ListItem from '@material-ui/core/ListItem';
import Container from '@material-ui/core/Container';
import AppBar from '@material-ui/core/AppBar';
import Toolbar from '@material-ui/core/Toolbar';
import IconButton from '@material-ui/core/IconButton';
import Typography from '@material-ui/core/Typography';
import CloseIcon from '@material-ui/icons/Close';
import Slide from '@material-ui/core/Slide';
import Grid from '@material-ui/core/Grid';
import Accordion from '@material-ui/core/Accordion';
import AccordionSummary from '@material-ui/core/AccordionSummary';
import AccordionDetails from '@material-ui/core/AccordionDetails';
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';

import pink from '@material-ui/core/colors/pink';

const useStyles = makeStyles((theme) => ({
	appBar: {
		position: 'relative',
	},
	title: {
		marginLeft: theme.spacing(2),
		flex: 1,
		fontWeight: 'bold',
	},
	dialogTitle: {
		fontWeight: 'bold',
	},
	screenList: {
		flexWrap: 'nowrap',
		transform: 'translateZ(0)',
	},
	metaLink: {
		color: pink[500],
		borderColor: pink[500],
		border: '1px solid ',
		padding: '1px',
		textDecoration: 'none',
		fontWeight: 'normal',
	},
	dialogLinks: {
		color: pink[500],
	},
}));

const Transition = React.forwardRef(function Transition(props, ref) {
	return <Slide direction="up" ref={ref} {...props} />;
});

export default function FullScreenDialog({
	gameName,
	gameInfo,
	genre,
	screen,
	handleClose,
	open,
}) {
	// truncate description text
	// var content = gameInfo.description_raw.trim();
	// content = content.split(' ').slice(0, 150);
	// content = content.join(' ') + ('.' ? '.' : '');
	// let elem = content;

	const classes = useStyles();

	return (
		<div>
			<Dialog
				fullScreen
				open={open}
				onClose={handleClose}
				TransitionComponent={Transition}
			>
				<AppBar
					className={classes.appBar}
					style={{ backgroundColor: '#291755' }}
				>
					<Toolbar>
						<IconButton
							edge="start"
							color="inherit"
							onClick={handleClose}
							aria-label="close"
						>
							<CloseIcon />
						</IconButton>
						<Typography variant="h6" className={classes.title}>
							{gameName}
						</Typography>
					</Toolbar>
				</AppBar>
				<div style={{ backgroundColor: '#291755' }}>
					<Container>
						<Grid
							container
							spacing={3}
							style={{
								padding: '1em',
								paddingBottom: 0,
							}}
						>
							<Grid item sm={5}>
								<div style={{ height: 'auto', width: '100%' }}>
									<img
										src={gameInfo.background_image}
										alt=""
										style={{
											height: '100%',
											width: '100%',
										}}
									/>
								</div>
							</Grid>

							<Grid item sm={5}>
								<Accordion style={{ backgroundColor: '#e91e63' }}>
									<AccordionSummary expandIcon={<ExpandMoreIcon />}>
										<Typography className={classes.dialogTitle}>
											Description
										</Typography>
									</AccordionSummary>
									<AccordionDetails>
										<p>{gameInfo.description_raw}</p>
									</AccordionDetails>
								</Accordion>

								<Grid container style={{ justifyContent: 'center' }}>
									<Grid container>
										<Grid item xs={6}>
											<p>
												<span className={classes.dialogTitle}>Developer</span>{' '}
												<br />
												{gameInfo.developers[0].name}
											</p>
										</Grid>
										<Grid item xs={6}>
											<p className={classes.paper}>
												<span className={classes.dialogTitle}>Publisher</span>
												<br />
												{gameInfo.publishers[0].name}
											</p>
										</Grid>
									</Grid>
									<Grid
										container
										// style={{ justifyContent: 'center' }}
									>
										<Grid item xs={6}>
											<p>
												<span className={classes.dialogTitle}>
													Release Date
												</span>
												<br />
												{gameInfo.released}
											</p>
										</Grid>
										<Grid item xs={6}>
											<p className={classes.paper}>
												<span className={classes.dialogTitle}>Metacritic</span>
												<br />
												{gameInfo.metacritic && gameInfo.metacritic_url ? (
													<a
														className={classes.metaLink}
														href={gameInfo.metacritic_url}
														target="_blank"
														rel="noreferrer"
													>
														{gameInfo.metacritic}
													</a>
												) : (
													'Not found'
												)}
											</p>
										</Grid>
									</Grid>
									{/* </Grid> */}
									<Grid
										container
										// style={{ justifyContent: 'center' }}
									>
										<Grid item xs={6}>
											<p className={classes.paper}>
												<span className={classes.dialogTitle}>Genres</span>
												<br />
												{genre[0] ? <span>{genre[0]}</span> : 'Not found'}
												<br />
												{genre[1] && <span>{genre[1]}</span>}
												<br />
												{genre[2] && <span>{genre[2]}</span>}
											</p>
										</Grid>
										<Grid item xs={6}>
											<p className={classes.paper}>
												<span className={classes.dialogTitle}>Links</span>
												<br />
												{gameInfo.website && gameInfo.reddit_url ? (
													<div>
														<a
															className={classes.dialogLinks}
															href={gameInfo.website}
															target="_blank"
															rel="noreferrer"
														>
															Official Website
														</a>
														<br />
														<a
															className={classes.dialogLinks}
															href={gameInfo.reddit_url}
															target="_blank"
															rel="noreferrer"
														>
															Subreddit
														</a>
													</div>
												) : (
													'Not found'
												)}
											</p>
										</Grid>
									</Grid>
								</Grid>
							</Grid>
						</Grid>
					</Container>
				</div>
				<div style={{ backgroundColor: '#291755' }}>
					<Container>
						<p
							style={{
								padding: '1em',
								marginTop: '1em',
							}}
						>
							<span className={classes.dialogTitle}>Screenshots</span>
							<br />
							<ImageList className={classes.screenList} cols={1.7}>
								{screen
									? screen.map((item) => (
											<ImageListItem key={item.image}>
												<img src={item.image} alt="" />
											</ImageListItem>
									  ))
									: 'Not found '}{' '}
								;
							</ImageList>
						</p>
					</Container>
				</div>
			</Dialog>
		</div>
	);
}
