import React from 'react';
import NavBar from './components/NavBar';
import Search from './components/Search';
import { makeStyles } from '@material-ui/core';

import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import About from './components/About';

const useStyles = makeStyles(() => ({
	titleMargin: {
		padding: 5,
		textTransform: 'uppercase',
		marginTop: 10,
		color: 'white',
		textDecoration: 'none',
		fontSize: '1.5em',
	},
	linkButton: {
		marginRight: 10,
		fontSize: '1em',
		alignSelf: 'center',
		color: 'white',
		textTransform: 'uppercase',
		textDecoration: 'none',
		'&:hover': {
			textDecoration: 'underline',
		},
	},
	searchMargin: {
		marginTop: 20,
		marginBottom: 40,
		width: '100%',
		alignSelf: 'center',
	},
	buttonMargin: {
		marginTop: 20,
	},
	footer: {
		textAlign: 'center',
		marginTop: 20,
	},
}));

function App() {
	const classes = useStyles();

	return (
		<Router>
			<div>
				<NavBar classes={classes} />
				<Switch>
					<Route exact path="/">
						<Search classes={classes} />
					</Route>
					<Route path="/about">
						<About />
					</Route>
				</Switch>
			</div>
		</Router>
	);
}

export default App;
